# Common PoC practices that are NOT production-ready

POC_ANTIPATTERNS = {
    "hardcoded_api_key": {
        "poc_practice": "API key in environment variable or .env file in repo",
        "production_requirement": "Secret management service (AWS Secrets Manager, Vault); key rotation policy",
        "exit_criterion": "TECH-SEC-01: All secrets managed via approved secret store; no credentials in code or config files",
    },
    "single_provider_dependency": {
        "poc_practice": "Single LLM provider; if it goes down, feature is down",
        "production_requirement": "Fallback provider configured; circuit breaker implemented",
        "exit_criterion": "OPS-04: Fallback to secondary provider or rule-based mode demonstrated in chaos test",
    },
    "no_rate_limiting": {
        "poc_practice": "Direct user → API; no token budget enforcement",
        "production_requirement": "Per-user session token budget; global request rate limiter; cost ceiling enforcement",
        "exit_criterion": "OPS-02: Token budget per session enforced; cost ceiling alert active at 80%",
    },
    "eval_on_test_set_only": {
        "poc_practice": "Accuracy measured on dev benchmark; no production traffic eval",
        "production_requirement": "Weekly eval on production-sampled interactions; eval set versioned and growing",
        "exit_criterion": "TECH-01: Accuracy eval running on production sample before launch; baseline established",
    },
    "no_audit_log": {
        "poc_practice": "Outputs not logged or logged ephemerally",
        "production_requirement": "Pseudonymised interaction logs retained for audit period; searchable by session ID",
        "exit_criterion": "DATA-03: Audit log active in production; retention and pseudonymisation verified",
    },
    "manual_deployment": {
        "poc_practice": "Deploy by running script on developer laptop",
        "production_requirement": "CI/CD pipeline with eval gate; rollback procedure; blue/green or canary deployment",
        "exit_criterion": "OPS-03: CI/CD pipeline deployed; rollback tested; eval gate blocking on critical criteria",
    },
}

# Go / No-Go decision record template

